prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskAName ?taskBName ?betweenName ?betweenId WHERE {
  ?model a bboExt:Model ;
         bbo:name ?modelName ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" .

  ?taskA a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?taskAName .
  FILTER(CONTAINS(LCASE(STR(?taskAName)), LCASE("Musterrohstoff oder bereits existentes Material  mit ähnlichen Informationen erfragen")))

  ?taskB a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?taskBName .
  FILTER(CONTAINS(LCASE(STR(?taskBName)), LCASE("Produktstart, Eigenschaften, Spezifikationen, Zeichnung erfragen")))

  ?taskA ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?between .
  ?between ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?taskB .

  ?between a bboExt:ChoreographyTask ;
            bbo:name ?betweenName ;
            bbo:id ?betweenId .

  FILTER(?between != ?taskA && ?between != ?taskB)
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskA ?taskAName ?taskB ?taskBName ?choreo {
  ?model a bboExt:Model ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" ;
         tai:belongsTo ?org .
  ?model tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?model .

  ?taskA a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?taskAName .
  FILTER(CONTAINS(LCASE(STR(?taskAName)), LCASE("Musterrohstoff oder bereits existentes Material")))

  ?taskB a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?taskBName .
  FILTER(CONTAINS(LCASE(STR(?taskBName)), LCASE("Produktstart")))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?name ?comment WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .

  ?elem a ?type ;
        tai:belongsTo ?choreo ;
        bbo:name ?name .
  FILTER(?name != "")

  FILTER(
    CONTAINS(LCASE(STR(?name)), LCASE("Musterrohstoff")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("Produktstart")) ||
    CONTAINS(LCASE(STR(?name)), LCASE("Material"))
  )

  OPTIONAL { ?elem rdfs:comment ?comment . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?type ?name ?id ?label WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "3d0f07f9b84c4e31bbca562f472c8885" ;
         tai:belongsTo ?org .
  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .

  ?elem a ?type ; tai:belongsTo ?choreo .

  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem bbo:id ?id . }
  OPTIONAL { ?elem rdfs:label ?label . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?normId ?origId ?orgId ?created WHERE {
  ?model a bboExt:Model ;
         tai:belongsTo ?org .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?org tai:organizationId ?orgId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  FILTER(
    (BOUND(?normId) && CONTAINS(LCASE(STR(?normId)), LCASE("3d0f07f9b84c4e31bbca562f472c8885"))) ||
    (BOUND(?origId) && CONTAINS(LCASE(STR(?origId)), LCASE("3d0f07f9b84c4e31bbca562f472c8885")))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?taskType ?name ?label ?id WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" ;
         tai:belongsTo ?org .

  ?choreo a bboExt:Choreography ; tai:belongsTo ?model .

  ?task a ?taskType ; tai:belongsTo ?choreo .
  FILTER(?taskType IN (bboExt:ChoreographyTask, bboExt:StartEvent, bboExt:IntermediateCatchEvent, bboExt:EndEvent, bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))

  OPTIONAL { ?task bbo:name ?name . }
  OPTIONAL { ?task rdfs:label ?label . }
  OPTIONAL { ?task bbo:id ?id . }
}
ORDER BY ?task
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?type ?name ?id WHERE {
  ?model a bboExt:Model ; tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" ; tai:belongsTo ?org .
  ?container tai:belongsTo ?model .
  {
    ?container a bboExt:Choreography .
  }
  UNION
  {
    ?container a bboExt:Collaboration .
  }
  UNION
  {
    ?container a bboExt:Definitions .
  }

  ?elem tai:belongsTo ?container .
  ?elem a ?type .

  OPTIONAL { ?elem bbo:name ?name . }
  OPTIONAL { ?elem bbo:id ?id . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?edge ?src ?tgt ?srcName ?tgtName WHERE {
  ?model a bboExt:Model ;
         tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" ;
         tai:belongsTo ?org .

  ?container tai:belongsTo ?model .
  ?edge a bbo:SequenceFlow ; tai:belongsTo ?container .

  ?edge bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .

  OPTIONAL { ?src bbo:name ?srcName . }
  OPTIONAL { ?tgt bbo:name ?tgtName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskA ?taskB ?between ?betweenName WHERE {
  ?model a bboExt:Model ; tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?taskA ;
        bbo:has_targetRef ?taskB .

  ?taskA tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?model .

  OPTIONAL { ?between bbo:name ?betweenName }

  FILTER(BOUND(?taskA) && BOUND(?taskB))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?edge ?src ?tgt ?srcName ?tgtName WHERE {
  ?model a bboExt:Model ; tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .

  # find any node that is contained (possibly transitively) up to the model
  ?src (tai:belongsTo)+ ?model .
  ?tgt (tai:belongsTo)+ ?model .

  ?edge a bbo:SequenceFlow ;
        bbo:has_sourceRef ?src ;
        bbo:has_targetRef ?tgt .

  OPTIONAL { ?src bbo:name ?srcName . }
  OPTIONAL { ?tgt bbo:name ?tgtName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?between ?betweenName ?musterName ?prodStartName ?hopsFromMuster WHERE {
  ?model a bboExt:Model ; tai:originalId "3d0f07f9b84c4e31bbca562f472c8885" .

  ?muster (tai:belongsTo)+ ?model ; bbo:name ?musterName .
  FILTER(CONTAINS(STR(?musterName), "Musterrohstoff"))

  ?prodStart (tai:belongsTo)+ ?model ; bbo:name ?prodStartName .
  FILTER(CONTAINS(LCASE(STR(?prodStartName)), "produktstart"))

  ?between bbo:name ?betweenName .
  FILTER(?between != ?muster && ?between != ?prodStart)

  {
    # hopsFromMuster = 1
    BIND(1 AS ?hopsFromMuster)
    ?muster ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?between .
    FILTER NOT EXISTS { ?muster ((^bbo:has_sourceRef)/bbo:has_targetRef)+{0} ?between }
  }
  UNION
  {
    BIND(2 AS ?hopsFromMuster)
    ?muster ((^bbo:has_sourceRef)/bbo:has_targetRef){2} ?between .
  }
  UNION
  {
    BIND(3 AS ?hopsFromMuster)
    ?muster ((^bbo:has_sourceRef)/bbo:has_targetRef){3} ?between .
  }
  UNION
  {
    BIND(4 AS ?hopsFromMuster)
    ?muster ((^bbo:has_sourceRef)/bbo:has_targetRef){4} ?between .
  }
  UNION
  {
    BIND(5 AS ?hopsFromMuster)
    ?muster ((^bbo:has_sourceRef)/bbo:has_targetRef){5} ?between .
  }

  ?between ((^bbo:has_sourceRef)/bbo:has_targetRef)+ ?prodStart .
}
ORDER BY ?hopsFromMuster
LIMIT 25
